public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    String[] businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};
    java.util.List<String> validCoupons = new java.util.ArrayList<>();

    for (int i = 0; i < code.length; i++) {
        String c = code[i];
        String business = businessLine[i];
        boolean active = isActive[i];

        if (c != null && !c.isEmpty() && c.matches("^[\\w]+$") && business != null && businessOrder.contains(business) && active) {
            validCoupons.add(c);
        }
    }

    validCoupons.sort((a, b) -> {
        int businessIndexA = java.util.Arrays.asList(businessOrder).indexOf(a);
        int businessIndexB = java.util.Arrays.asList(businessOrder).indexOf(b);
        if (businessIndexA != businessIndexB) {
            return Integer.compare(businessIndexA, businessIndexB);
        } else {
            return a.compareTo(b);
        }
    });

    return validCoupons.toArray(new String[0]);
}
